+fn status_str(s: doctor::Status) -> &'static str {
+    match s {
+        doctor::Status::Ok   => "ok",
+        doctor::Status::Warn => "warn",
+        doctor::Status::Fail => "fail",
+        doctor::Status::Info => "info",
+    }
